{"action":"write","content":"const http = require('http');
const fs = require('fs');
const path = require('path');
const WebSocket = require('ws');
const si = require('systeminformation');

const PORT = process.env.PORT || 3000;
const POLL_INTERVAL = 1000; // 1 second
const MAX_HISTORY = 60; // Keep last 60 data points

// MIME types for static files
const mimeTypes = {
  '.html': 'text/html',
  '.js': 'application/javascript',
  '.css': 'text/css',
  '.json': 'application/json',
  '.png': 'image/png',
  '.jpg': 'image/jpeg',
  '.gif': 'image/gif',
  '.svg': 'image/svg+xml',
  '.ico': 'image/x-icon'
};

// Create HTTP server
const server = http.createServer((req, res) => {
  let filePath = req.url === '/' ? '/index.html' : req.url;
  filePath = path.join(__dirname, 'public', filePath);

  const ext = path.extname(filePath).toLowerCase();
  const contentType = mimeTypes[ext] || 'application/octet-stream';

  fs.readFile(filePath, (err, content) => {
    if (err) {
      if (err.code === 'ENOENT') {
        res.writeHead(404, { 'Content-Type': 'text/plain' });
        res.end('Not Found');
      } else {
        res.writeHead(500, { 'Content-Type': 'text/plain' });
        res.end('Server Error');
      }
    } else {
      res.writeHead(200, { 'Content-Type': contentType });
      res.end(content);
    }
  });
});

// Create WebSocket server attached to HTTP server
const wss = new WebSocket.Server({ server });

// Store connected clients
const clients = new Set();

wss.on('connection', (ws) => {
  console.log('New WebSocket client connected');
  clients.add(ws);

  ws.on('close', () => {
    console.log('WebSocket client disconnected');
    clients.delete(ws);
  });

  ws.on('error', (err) => {
    console.error('WebSocket error:', err.message);
    clients.delete(ws);
  });
});

// Broadcast data to all connected clients
function broadcast(data) {
  const message = JSON.stringify(data);
  clients.forEach((client) => {
    if (client.readyState === WebSocket.OPEN) {
      client.send(message);
    }
  });
}

// Collect and broadcast system metrics
async function collectMetrics() {
  try {
    const [cpuData, memData] = await Promise.all([
      si.currentLoad(),
      si.mem()
    ]);

    const metrics = {
      timestamp: new Date().toISOString(),
      cpu: {
        usagePercent: parseFloat(cpuData.currentLoad.toFixed(1))
      },
      memory: {
        total: memData.total,
        used: memData.used,
        free: memData.free,
        usagePercent: parseFloat(((memData.used / memData.total) * 100).toFixed(1))
      }
    };

    broadcast(metrics);
  } catch (err) {
    console.error('Error collecting metrics:', err.message);
  }
}

// Start metrics collection loop
const metricsInterval = setInterval(collectMetrics, POLL_INTERVAL);

// Initial collection
collectMetrics();

// Graceful shutdown
process.on('SIGINT', () => {
  console.log('\nShutting down server...');
  clearInterval(metricsInterval);
  wss.close(() => {
    server.close(() => {
      process.exit(0);
    });
  });
});

server.listen(PORT, () => {
  console.log(`Server running at http://localhost:${PORT}`);
  console.log(`WebSocket server ready on ws://localhost:${PORT}`);
});
