{"action":"write","content":"* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
  background: linear-gradient(135deg, #1a1a2e 0%, #16213e 100%);
  color: #e0e0e0;
  min-height: 100vh;
}

.container {
  max-width: 1200px;
  margin: 0 auto;
  padding: 20px;
}

header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 30px;
  padding-bottom: 20px;
  border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}

header h1 {
  font-size: 2rem;
  font-weight: 300;
  letter-spacing: 2px;
  color: #fff;
}

.status {
  display: flex;
  align-items: center;
  gap: 20px;
  font-size: 0.9rem;
}

#connection-status {
  padding: 6px 12px;
  border-radius: 20px;
  font-weight: 500;
  font-size: 0.85rem;
  transition: all 0.3s ease;
}

#connection-status.connected {
  background: rgba(46, 204, 113, 0.2);
  color: #2ecc71;
  border: 1px solid rgba(46, 204, 113, 0.3);
}

#connection-status.disconnected {
  background: rgba(231, 76, 60, 0.2);
  color: #e74c3c;
  border: 1px solid rgba(231, 76, 60, 0.3);
}

#last-update {
  color: #888;
  font-size: 0.85rem;
}

.dashboard {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(450px, 1fr));
  gap: 25px;
  margin-bottom: 30px;
}

.card {
  background: rgba(255, 255, 255, 0.05);
  border-radius: 16px;
  padding: 25px;
  border: 1px solid rgba(255, 255, 255, 0.1);
  backdrop-filter: blur(10px);
  transition: transform 0.3s ease, box-shadow 0.3s ease;
}

.card:hover {
  transform: translateY(-2px);
  box-shadow: 0 10px 40px rgba(0, 0, 0, 0.3);
}

.card-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 15px;
}

.card-header h2 {
  font-size: 1.2rem;
  font-weight: 400;
  color: #fff;
}

.metric-value {
  font-size: 2.5rem;
  font-weight: 700;
  color: #fff;
}

#cpu-value {
  color: #3498db;
}

#memory-value {
  color: #2ecc71;
}

.memory-details {
  text-align: center;
  margin-bottom: 15px;
  color: #aaa;
  font-size: 0.9rem;
}

.chart-container {
  position: relative;
  height: 250px;
  width: 100%;
}

footer {
  text-align: center;
  padding-top: 20px;
  border-top: 1px solid rgba(255, 255, 255, 0.1);
  color: #666;
  font-size: 0.85rem;
}

@media (max-width: 600px) {
  .dashboard {
    grid-template-columns: 1fr;
  }

  header {
    flex-direction: column;
    gap: 15px;
    text-align: center;
  }

  .metric-value {
    font-size: 2rem;
  }
}
