  };

  // Format bytes to human readable
  function formatBytes(bytes) {
    if (bytes === 0) return '0 B';
    const k = 1024;
    const sizes = ['B', 'KB', 'MB', 'GB', 'TB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  }

  // Format time
  function formatTime(date) {
    return date.toLocaleTimeString();
  }

  // Initialize charts
  function initCharts() {
    const commonOptions = {
      responsive: true,
      maintainAspectRatio: false,
      animation: {
        duration: 750,
        easing: 'linear'
      },
      interaction: {
        intersect: false,
        mode: 'index'
      },
      plugins: {
        legend: {
          display: false
        },
        tooltip: {
          backgroundColor: 'rgba(0, 0, 0, 0.8)',
          titleColor: '#fff',
          bodyColor: '#fff',
          borderColor: 'rgba(255, 255, 255, 0.1)',
          borderWidth: 1,
          padding: 10,
          displayColors: false,
          callbacks: {
            title: function(context) {
              return 'Time: ' + context[0].label;
            },
            label: function(context) {
              return context.parsed.y.toFixed(1) + '%';
            }
          }
        }
      },
      scales: {
        x: {
          grid: {
            color: 'rgba(255, 255, 255, 0.05)',
            drawBorder: false
          },
          ticks: {
            color: '#888',
            maxTicksLimit: 8,
            maxRotation: 0
          }
        },
        y: {
          min: 0,
          max: 100,
          grid: {
            color: 'rgba(255, 255, 255, 0.05)',
            drawBorder: false
          },
          ticks: {
            color: '#888',
            callback: function(value) {
              return value + '%';
            }
          }
        }
      }
    };

    // CPU Chart
    const cpuCtx = document.getElementById('cpu-chart').getContext('2d');
    cpuChart = new Chart(cpuCtx, {
      type: 'line',
      data: {
        labels: cpuData.labels,
        datasets: [{
          label: 'CPU Usage',
          data: cpuData.values,
          borderColor: '#3498db',
          backgroundColor: 'rgba(52, 152, 219, 0.1)',
          borderWidth: 2,
          fill: true,
          tension: 0.4,
          pointRadius: 0,
          pointHoverRadius: 4,
          pointHoverBackgroundColor: '#3498db'
        }]
      },
      options: commonOptions
    });

    // Memory Chart
    const memoryCtx = document.getElementById('memory-chart').getContext('2d');
    memoryChart = new Chart(memoryCtx, {
      type: 'line',
      data: {
        labels: memoryData.labels,
        datasets: [{
          label: 'Memory Usage',
          data: memoryData.values,
          borderColor: '#2ecc71',
          backgroundColor: 'rgba(46, 204, 113, 0.1)',
          borderWidth: 2,
          fill: true,
          tension: 0.4,
          pointRadius: 0,
          pointHoverRadius: 4,
          pointHoverBackgroundColor: '#2ecc71'
        }]
      },
      options: commonOptions
    });
  }

  // Update charts with new data
  function updateCharts(timestamp, cpuPercent, memoryPercent) {
    const timeLabel = formatTime(new Date(timestamp));

    // Update CPU data
    cpuData.labels.push(timeLabel);
    cpuData.values.push(cpuPercent);

    if (cpuData.labels.length > MAX_DATA_POINTS) {
      cpuData.labels.shift();
      cpuData.values.shift();
    }

    cpuChart.data.labels = cpuData.labels;
    cpuChart.data.datasets[0].data = cpuData.values;
    cpuChart.update('none'); // Update without full re-render for performance

    // Update Memory data
    memoryData.labels.push(timeLabel);
    memoryData.values.push(memoryPercent);

    if (memoryData.labels.length > MAX_DATA_POINTS) {
      memoryData.labels.shift();
      memoryData.values.shift();
    }

    memoryChart.data.labels = memoryData.labels;
    memoryChart.data.datasets[0].data = memoryData.values;
    memoryChart.update('none');
  }

  // Update DOM elements
  function updateDisplay(data) {
    cpuValueEl.textContent = data.cpu.usagePercent.toFixed(1) + '%';
    memoryValueEl.textContent = data.memory.usagePercent.toFixed(1) + '%';
    memoryUsedEl.textContent = formatBytes(data.memory.used);
    memoryTotalEl.textContent = formatBytes(data.memory.total);
    lastUpdateEl.textContent = 'Last update: ' + formatTime(new Date(data.timestamp));
  }

  // WebSocket connection
  let ws = null;
  let reconnectTimer = null;

  function connect() {
    const protocol = window.location.protocol === 'https:' ? 'wss:' : 'ws:';
    const wsUrl = protocol + '//' + window.location.host;

    ws = new WebSocket(wsUrl);

    ws.onopen = function() {
      console.log('WebSocket connected');
      connectionStatusEl.textContent = 'Connected';
      connectionStatusEl.className = 'connected';
      clearTimeout(reconnectTimer);
    };

    ws.onmessage = function(event) {
      try {
        const data = JSON.parse(event.data);
        updateDisplay(data);
        updateCharts(data.timestamp, data.cpu.usagePercent, data.memory.usagePercent);
      } catch (err) {
        console.error('Error parsing message:', err);
      }
    };

    ws.onclose = function() {
      console.log('WebSocket disconnected');
      connectionStatusEl.textContent = 'Disconnected';
      connectionStatusEl.className = 'disconnected';
      reconnectTimer = setTimeout(connect, RECONNECT_INTERVAL);
    };

    ws.onerror = function(err) {
      console.error('WebSocket error:', err);
      ws.close();
    };
  }

  // Initialize
  document.addEventListener('DOMContentLoaded', function() {
    initCharts();
    connect();
  });

})();
","path":"public/app.js"}

